import { registerMvuSchema } from 'https://testingcf.jsdelivr.net/gh/StageDog/tavern_resource/dist/util/mvu_zod.js';

// Chỉ giữ lại các cấp bậc tu luyện thông dụng
const DanhSachTuVi = z.enum([
  'Người phàm', 'Không rõ',
  'Luyện khí', 'Trúc cơ', 'Toàn chiếu', 'Khai quang', 'Dung hợp', 'Tâm động', 'Linh tịch', 'Kim đan',
  'Nguyên anh', 'Xuất khiếu', 'Phân thần', 'Hợp thể', 'Độ kiếp', 'Đại thừa', 'Bán tiên', 'Thần tiên',
  'Luyện da', 'Luyện thịt', 'Luyện gân', 'Rèn xương', 'Thay tủy', 'Thay máu', 'Luyện nội tạng', 'Thông mạch',
  'Kim thân', 'Ngưng phách', 'Thần lực', 'Quy tàng', 'Bất hoại', 'Tích huyết', 'Thiên biến', 'Thân thể thành thánh',
  'Đồng sinh', 'Tú tài', 'Cử nhân', 'Dưỡng khí', 'Mở mang trí tuệ', 'Hiểu lý lẽ', 'Lập tâm', 'Thành ý',
  'Hạo nhiên', 'Cách vật', 'Trí tri', 'Tu thân', 'Tề gia', 'Trị quốc', 'Dẹp loạn', 'Lời nói thành luật',
  'Tụ linh', 'Thông trí', 'Luyện xương ngang', 'Yêu đan', 'Hóa hình', 'Ngưng sát', 'Rèn thể', 'Nuốt chửng',
  'Ma anh', 'Ly thức', 'Cướp xác', 'Dung hồn', 'Qua kiếp nạn', 'Bất diệt', 'Thiên ma', 'Tổ ma hỗn độn',
  'Thánh nhân ngoài đạo'
]).prefault('Không rõ');

export const Schema = z.object({
  CapBocTuLuyen: DanhSachTuVi,
  ConDuongTuLuyen: z.string().prefault('Không rõ'),

  TheGioi: z.object({
    ThoiGian: z.string().prefault('Ngày mùng 1 tháng Giêng'),
    DiaDiem: z.string().prefault('Nơi chưa rõ'),
    ThoiTiet: z.string().prefault('Trời nắng'),
  }).prefault({}),

  DanhSachNuChinh: z.partialRecord(
    z.enum([
      'Phượng Lý Hy', 'Cố Cửu Từ', 'Diêu Tuyết Trúc', 'Mộc Thi Quân', 'Cơ Như Tuyết', 'Bùi Chiêu Tễ',
      'Hàn Ngưng Yên', 'Khâu Nhàn Trinh', 'Cố Tương Nam', 'Tào Thanh Nhàn', 'Tần Vũ Bình', 'Giếng Thượng Trí Ngạn',
      'Ký Nguyệt Tầm', 'Vũ Huyên', 'Tô Mị Nhi', 'Mộ Dung Lam', 'Cố Tuyết Diên', 'Tào Vũ Sầm'
    ]),
    z.object({
      TuVi: DanhSachTuVi,
      MonPhai: z.string().prefault('Không rõ'),
      TrangPhuc: z.object({
        AoTren: z.string().prefault('Không rõ'),
        QuanVay: z.string().prefault('Không rõ'),
        TatChan: z.string().prefault('Không rõ'),
        GiayDep: z.string().prefault('Không rõ'),
        PhuKien: z.string().prefault('Không rõ'),
      }).prefault({}),
      CoThe: z.object({
        Mieng: z.string().prefault('Không rõ'),
        Nguc: z.string().prefault('Không rõ'),
        Bung: z.string().prefault('Không rõ'),
        Mong: z.string().prefault('Không rõ'),
        Nach: z.string().prefault('Không rõ'),
        VungKin: z.string().prefault('Không rõ'),
        CuaSau: z.string().prefault('Không rõ'),
        Chan: z.string().prefault('Không rõ'),
        BanChan: z.string().prefault('Không rõ'),
      }).prefault({}),
      TinhCam: z.coerce.number().transform(v => _.clamp(v, -100, 100)).prefault(0),
      DoSaDoa: z.coerce.number().transform(v => _.clamp(v, 0, 1000)).prefault(0),
      MangThai: z.boolean().prefault(false),
      SuyNghi: z.string().prefault(''),
      LichSuAnAi: z.object({
        DoiTuong: z.string().prefault('Không có'),
        TomTat: z.string().prefault(''),
      }).prefault({}),
      AnhDaiDien: z.enum(['Bình thường', 'Sa đọa', 'Có bầu', 'Sa đọa và có bầu']).prefault('Bình thường'),
    }).prefault({})
  ).prefault({}),

  DanhSachNuPhu: z.record(
    z.string(),
    z.object({
      NhomTuoi: z.enum(['Bé gái', 'Thiếu nữ', 'Phụ nữ']).prefault('Phụ nữ'),
      TuVi: DanhSachTuVi,
      MonPhai: z.string().prefault('Không rõ'),
      TrangPhuc: z.object({
        AoTren: z.string().prefault('Không rõ'),
        QuanVay: z.string().prefault('Không rõ'),
        TatChan: z.string().prefault('Không rõ'),
        GiayDep: z.string().prefault('Không rõ'),
        PhuKien: z.string().prefault('Không rõ'),
      }).prefault({}),
      CoThe: z.object({
        Mieng: z.string().prefault('Không rõ'),
        Nguc: z.string().prefault('Không rõ'),
        Bung: z.string().prefault('Không rõ'),
        Mong: z.string().prefault('Không rõ'),
        Nach: z.string().prefault('Không rõ'),
        VungKin: z.string().prefault('Không rõ'),
        CuaSau: z.string().prefault('Không rõ'),
        Chan: z.string().prefault('Không rõ'),
        BanChan: z.string().prefault('Không rõ'),
      }).prefault({}),
      TinhCam: z.coerce.number().transform(v => _.clamp(v, -100, 100)).prefault(0),
      DoSaDoa: z.coerce.number().transform(v => _.clamp(v, 0, 1000)).prefault(0),
      MangThai: z.boolean().prefault(false),
      SuyNghi: z.string().prefault(''),
    }).prefault({})
  ).prefault({}),

  DanhSachNam: z.record(
    z.string(),
    z.object({
      TheLuc: z.string().prefault('Không rõ'),
      NhamNhe: z.string().prefault('Không có'),
      TienDoChiemDoat: z.enum(['Mới để ý', 'Sinh tà niệm', 'Đã chiếm được', 'Dạy dỗ nô lệ', 'Khiến phục tùng', 'Say đắm không rời']).prefault('Mới để ý'),
    }).prefault({})
  ).prefault({}),

  NguoiChoi: z.object({
    TenGoi: z.string().prefault('{{User}}'),
    TuVi: DanhSachTuVi,
    MonPhai: z.string().prefault('Không rõ'),
    TheLuc: z.string().prefault('Không có'),
    HauCung: z.record(z.string(), z.string()).prefault({}),
    NguoiHau: z.record(z.string(), z.string()).prefault({}),
    ConCai: z.record(z.string(), z.string()).prefault({}),
  }).prefault({}),

  CotTruyen: z.object({
    ChuDeTruyen: z.enum(['NTR', 'NTL', 'Thuần ái', 'Tự do']).prefault('Thuần ái'),
    GiaiDoanTruyen: z.string().regex(/^(Nhân Tông|Thiên Tông|Kiếm Tông|Cầm Tông|Tây Vực|Thiên Huyền|Đông Doanh|Thần Long)_(Một|Hai|Ba|Bốn|Năm|Sáu|Bảy|Tám|Chín|Mười)$/).prefault('Nhân Tông Một'),
  }).prefault({}),
});

$(() => {
  registerMvuSchema(Schema);
})

