<script type="module">
/* --- Phần Logic cốt lõi --- */
const IMAGE_POOLS = {
  'DanhSachNuChinh': {
    'Bùi Chiêu Tễ': {
      'Bình thường': 'https://i.postimg.cc/gJt3dGb6/AI-Image2990604.png',
