    },
    'fallback': 'https://images.unsplash.com/photo-1544890225-2f3faec4cb60?auto=format&fit=crop&q=80&w=832&h=1216'
  },
  'DanhSachNuPhu': {
    '_AnhDocLap': {
      'Diêu Linh Nhi': 'https://i.postimg.cc/DfRt1y6M/AI-Image1255254.png',
      'Ngọc Thanh': 'https://files.catbox.moe/reev0o.png'
    },
    'Bé gái': [
      'https://files.catbox.moe/kew3l4.png',
      'https://files.catbox.moe/22undq.png',
      'https://files.catbox.moe/qmh5bg.png'
    ],
    'Thiếu nữ': [
      'https://files.catbox.moe/fyuuy1.png',
      'https://files.catbox.moe/uy1n3h.png',
      'https://files.catbox.moe/kv2i3i.png',
