    ]
  }
};

const scRandomIndices = {};

function hashCode(str) {
  let hash = 0;
  for (let i = 0, len = str.length; i < len; i++) {
    let chr = str.charCodeAt(i);
    hash = (hash << 5) - hash + chr;
    hash |= 0;
  }
  return Math.abs(hash);
}

function getCharacterImage(type, data, name) {
  if (type === 'DanhSachNuChinh') {
    const state = data.AnhDaiDien || 'Bình thường';
    const charPool = IMAGE_POOLS['DanhSachNuChinh'][name];
    if (charPool && charPool[state]) {
      return charPool[state];
    }
    return IMAGE_POOLS['DanhSachNuChinh']['fallback'];
  } else if (type === 'DanhSachNuPhu') {
    const specialPool = IMAGE_POOLS['DanhSachNuPhu']['_AnhDocLap'];
    if (specialPool && specialPool[name]) {
      return specialPool[name];
    }
    const ageType = data.NhomTuoi || 'Phụ nữ';
    const pool = IMAGE_POOLS['DanhSachNuPhu'][ageType];
    if (pool && pool.length > 0) {
      if (scRandomIndices[name] === undefined) {
        scRandomIndices[name] = hashCode(name) % pool.length;
      }
      return pool[scRandomIndices[name]];
    }
    return IMAGE_POOLS['DanhSachNuChinh']['fallback'];
  }
  return '';
}

window.refreshCharacterImage = function(event, name, ageType) {
  event.stopPropagation();
  const pool = IMAGE_POOLS['DanhSachNuPhu'][ageType];
  if (pool && pool.length > 1) {
    let newIdx;
    do {
      newIdx = Math.floor(Math.random() * pool.length);
    } while (newIdx === scRandomIndices[name]);
    scRandomIndices[name] = newIdx;
    populateCharacterData();
  }
};

function populateCharacterData() {
  const all_variables = getAllVariables();
  const stat_data = _.get(all_variables, 'stat_data', {});
  const storyMode = _.get(stat_data, 'CotTruyen.ChuDeTruyen', 'Thuần ái');
  let themeH = 35;
  if(storyMode === 'NTR') themeH = 280;
  else if(storyMode === 'NTL') themeH = 0;
  else if(storyMode === 'Tự do') themeH = 200;
  document.documentElement.style.setProperty('--theme-h', themeH);

  $('#usr-name').text(_.get(stat_data, 'NguoiChoi.TenGoi', 'Không rõ'));
  $('#usr-realm').text(_.get(stat_data, 'NguoiChoi.TuVi', 'Người phàm'));
  $('#env-time').text(_.get(stat_data, 'TheGioi.ThoiGian', 'Không rõ thời gian'));
  $('#env-place').text(_.get(stat_data, 'TheGioi.DiaDiem', 'Không rõ địa điểm'));
  $('#env-weather').text(_.get(stat_data, 'TheGioi.ThoiTiet', 'Không rõ'));

  $('#sec-gongwei, #content-gongwei, #sec-kuaxia, #content-kuaxia, #sec-longyang, #content-longyang').hide();
  if (storyMode === 'Thuần ái') {
    $('#sec-gongwei, #content-gongwei').show();
  } else if (storyMode === 'NTL') {
    $('#sec-kuaxia, #content-kuaxia').show();
  } else if (storyMode === 'NTR') {
    $('#sec-longyang, #content-longyang').show();
  } else if (storyMode === 'Tự do') {
    $('#sec-gongwei, #content-gongwei, #sec-kuaxia, #content-kuaxia, #sec-longyang, #content-longyang').show();
  }

  renderCardList('DanhSachNuChinh', _.get(stat_data, 'DanhSachNuChinh', {}), $('#hy-container'));
  renderCardList('DanhSachNuPhu', _.get(stat_data, 'DanhSachNuPhu', {}), $('#sc-container'));
  renderTextList(_.get(stat_data, 'NguoiChoi.HauCung', {}), $('#gongwei-list'));
  renderTextList(_.get(stat_data, 'NguoiChoi.NguoiHau', {}), $('#kuaxia-list'));
  renderTextList(_.get(stat_data, 'DanhSachNam', {}), $('#longyang-list'), true);
}

function renderTextList(dataObj, $container, isComplex = false) {
  $container.empty();
  if(Object.keys(dataObj).length === 0) {
    $container.append('<div style="opacity:0.5; font-size:0.9em; text-align:center; padding:10px; grid-column: 1 / -1;">Trống rỗng</div>');
    return;
  }
  Object.entries(dataObj).forEach(([name, data]) => {
    let text = isComplex ? `${name} [Tiến độ: ${data.TienDoChiemDoat||'Không rõ'}]` : `${name} - ${data}`;
    $container.append(`<div class="info-item"><span class="info-value" style="font-size:0.9em;">${text}</span></div>`);
  });
}

function renderCardList(type, dataObj, $container) {
  $container.empty();
  if(Object.keys(dataObj).length === 0) {
    $container.append('<div style="opacity:0.5; padding: 20px;">Tạm thời chưa có ai</div>');
    return;
  }
  Object.entries(dataObj).forEach(([name, data]) => {
    const imgUrl = getCharacterImage(type, data, name);
    const favor = parseInt(data.TinhCam || 0);
    const favorPct = Math.max(0, Math.min(100, (favor + 100) / 2));
    const evil = parseInt(data.DoSaDoa || 0);
    const evilPct = Math.max(0, Math.min(100, (evil / 1000) * 100));
    let refreshBtnHtml = '';
    if (type === 'DanhSachNuPhu') {
      const specialPool = IMAGE_POOLS['DanhSachNuPhu']['_AnhDocLap'];
      if (!specialPool || !specialPool[name]) {
        const ageType = data.NhomTuoi || 'Phụ nữ';
        refreshBtnHtml = `<div class="refresh-img-btn" onclick="refreshCharacterImage(event, '${name}', '${ageType}')"><i class="fas fa-sync-alt"></i></div>`;
      }
    }
    const cardHtml = `
      <div class="character-card" data-name="${name}" data-type="${type}">
        ${refreshBtnHtml}
        <div class="card-img" style="background-image: url('${imgUrl}')"></div>
        <div class="card-info">
          <div class="card-name">${name}</div>
          <div class="card-realm">${data.TuVi || 'Người phàm'}</div>
          <div style="display:flex; flex-direction:column; gap:2px; margin-top:5px;">
            <div class="mini-progress-bar"><div class="mini-progress-fill fill-favor" style="width: ${favorPct}%"></div></div>
            <div class="mini-progress-bar"><div class="mini-progress-fill fill-evil" style="width: ${evilPct}%"></div></div>
          </div>
        </div>
      </div>
    `;
    const $card = $(cardHtml);
    $card.on('click', () => openModal(name, data, imgUrl, favorPct, evilPct));
    $container.append($card);
  });
}

function openModal(name, data, imgUrl, favorPct, evilPct) {
  const $modal = $('#char-modal');
  $('#m-img').css('background-image', `url('${imgUrl}')`);
  $('#m-name').text(name);
  $('#m-realm').text(data.TuVi || 'Người phàm');
  const heartIcon = `<svg class="svg-icon" width="16" height="16" viewBox="0 0 24 24"><path fill="hsl(340,80%,60%)" d="M12 21.35l-1.45-1.32C5.4 15.36 2 12.28 2 8.5 2 5.42 4.42 3 7.5 3c1.74 0 3.41.81 4.5 2.09C13.09 3.81 14.76 3 16.5 3 19.58 3 22 5.42 22 8.5c0 3.78-3.4 6.86-8.55 11.54L12 21.35z"/></svg>`;
  const skullIcon = `<svg class="svg-icon" width="16" height="16" viewBox="0 0 24 24"><path fill="hsl(280,70%,40%)" d="M12 2C6.48 2 2 6.48 2 12s4.48 10 10 10 10-4.48 10-10S17.52 2 12 2zm0 18c-4.41 0-8-3.59-8-8s3.59-8 8-8 8 3.59 8 8-3.59 8-8 8zm-2.5-9c.83 0 1.5-.67 1.5-1.5S10.33 8 9.5 8 8 8.67 8 9.5 9.5 11zm5 0c.83 0 1.5-.67 1.5-1.5S15.33 8 14.5 8 13 8.67 13 9.5 14.5 11zm-4.5 3h4v2h-4z"/></svg>`;

  // Vẽ trạng thái Dựng Văn (Mang thai) / Linh Thai SVG
  const getStatusSvg = (val) => {
    if (val === true) {
       return `<svg class="status-icon-svg" width="18" height="18" viewBox="0 0 24 24" fill="none" xmlns="http://www.w3.org/2000/svg">
                <path d="M12 22C16.4183 22 20 18.4183 20 14C20 9.58172 12 2 12 2C12 2 4 9.58172 4 14C4 18.4183 7.58172 22 12 22Z" fill="gold" opacity="0.8"/>
                <circle cx="12" cy="14" r="3" fill="white" opacity="0.9">
                  <animate attributeName="r" values="2.5;3.5;2.5" dur="2s" repeatCount="indefinite" />
                </circle>
              </svg>`;
    } else {
       return `<svg class="status-icon-svg" width="18" height="18" viewBox="0 0 24 24" fill="none" xmlns="http://www.w3.org/2000/svg">
                <path d="M12 22C16.4183 22 20 18.4183 20 14C20 9.58172 12 2 12 2C12 2 4 9.58172 4 14C4 18.4183 7.58172 22 12 22Z" stroke="rgba(255,255,255,0.2)" stroke-width="2"/>
                <path d="M9 14L15 14" stroke="rgba(255,255,255,0.2)" stroke-width="2" stroke-linecap="round"/>
              </svg>`;
    }
  };

  $('#m-favor').html(`
    <div class="detail-stat-row">
      <div class="detail-stat-label">${heartIcon} Tình cảm</div>
      <div class="detail-progress-track"><div class="detail-progress-fill fill-favor" id="modal-fill-favor" style="width: 0%"></div></div>
      <div class="detail-stat-value">${data.TinhCam || 0}</div>
    </div>
  `);
  $('#m-evil').html(`
    <div class="detail-stat-row">
      <div class="detail-stat-label">${skullIcon} Sa đọa</div>
      <div class="detail-progress-track"><div class="detail-progress-fill fill-evil" id="modal-fill-evil" style="width: 0%"></div></div>
      <div class="detail-stat-value">${data.DoSaDoa || 0}</div>
    </div>
  `);
  let detailsHtml = '';
  const filterKeys = ['TuVi', 'TinhCam', 'DoSaDoa', 'NhomTuoi', 'AnhDaiDien'];
  Object.entries(data).forEach(([k, v]) => {
    if(!filterKeys.includes(k) && typeof v !== 'object') {
      // Thay đổi hiển thị icon cho giá trị boolean
      let displayValue = v;
      if (typeof v === 'boolean') {
        displayValue = getStatusSvg(v);
      }
      detailsHtml += `<div><span style="opacity:0.6">${k}:</span> ${displayValue}</div>`;
    } else if (typeof v === 'object' && v !== null) {
      detailsHtml += `<div style="grid-column: 1 / -1; margin-top: 5px; color:hsla(var(--theme-h),60%,70%,1); border-bottom:1px solid rgba(255,255,255,0.1)">${k}</div>`;
      Object.entries(v).forEach(([subK, subV]) => {
        let subDisplayValue = subV;
        if (typeof subV === 'boolean') {
          subDisplayValue = getStatusSvg(subV);
        }
        detailsHtml += `<div><span style="opacity:0.6">${subK}:</span> ${subDisplayValue}</div>`;
      });
    }
  });
  $('#m-details').html(`<div class="detail-grid">${detailsHtml}</div>`);
  $modal.css('display', 'flex').hide().fadeIn(300, function() {
    setTimeout(() => {
      $('#modal-fill-favor').css('width', favorPct + '%');
      $('#modal-fill-evil').css('width', evilPct + '%');
    }, 50);
  });
}

async function init() {
  await waitGlobalInitialized('Mvu');
  populateCharacterData();
